mapper.insert:
insert into `ai_call_log` (
    scene_code, prompt_version, provider, model, creator_user_id, request_digest, request_preview,
    context_count, cache_hit, fallback_used, status, latency_ms, error_message, result_preview, created_at
)
values (
    #{sceneCode}, #{promptVersion}, #{provider}, #{model}, #{creatorUserId}, #{requestDigest}, #{requestPreview},
    #{contextCount}, #{cacheHit}, #{fallbackUsed}, #{status}, #{latencyMs}, #{errorMessage}, #{resultPreview}, #{createdAt}
)

mapper.select:
select 
from `ai_call_log`


        and scene_code = #{sceneCode}


        and status = #{status}


order by id desc
limit #{limit}
